function renderVibe() {
  var vibe = filterByDate(VIBE_DATA, dFrom, dTo);
  var totalSpend = vibe.reduce(function(s,r){return s+r.spend;},0);
  var totalImpressions = vibe.reduce(function(s,r){return s+r.impressions;},0);
  var avgCPM = totalImpressions > 0 ? (totalSpend/totalImpressions*1000).toFixed(2) : '0.00';
  var numDays = (new Set(vibe.map(function(r){return r.date;}))).size;
  var avgDailySpend = numDays > 0 ? totalSpend / numDays : 0;

  var html = '';
  html += '<div class="card"><h3>Total Spend</h3><div class="value">' + fmt(totalSpend) + '</div></div>';
  html += '<div class="card"><h3>Total Impressions</h3><div class="value">' + fmtN(totalImpressions) + '</div></div>';
  html += '<div class="card"><h3>Avg CPM</h3><div class="value">' + fmt(parseFloat(avgCPM)) + '</div></div>';
  html += '<div class="card"><h3>Avg Daily Spend</h3><div class="value">' + fmt(avgDailySpend) + '</div><div style="font-size:11px;color:var(--muted);margin-top:4px">Across ' + numDays + ' days</div></div>';
  html += '<div class="card"><h3>Avg Daily Impressions</h3><div class="value">' + fmtN(numDays > 0 ? Math.round(totalImpressions/numDays) : 0) + '</div></div>';
  document.getElementById('vibeCards').innerHTML = html;

  // Campaign breakdown by campaign
  var vCamps = {};
  vibe.forEach(function(r) {
    if (!vCamps[r.campaign]) vCamps[r.campaign] = {spend:0,impressions:0,days:0};
    vCamps[r.campaign].spend += r.spend;
    vCamps[r.campaign].impressions += r.impressions;
    vCamps[r.campaign].days += 1;
  });

  // Status for Vibe based on CPM efficiency and delivery consistency
  var vibeStatus = function(name, c) {
    var cpm = c.impressions > 0 ? c.spend / c.impressions * 1000 : 0;
    var isRetargeting = name.indexOf('Retargeting') !== -1;
    if (isRetargeting && cpm <= 22) return 'stable';
    if (!isRetargeting && cpm <= 15) return 'scale';
    if (!isRetargeting && cpm <= 20) return 'stable';
    return 'monitor';
  };

  var campHtml = '<table><thead><tr><th>Campaign</th><th style="text-align:right">Spend</th><th style="text-align:right">Impressions</th><th style="text-align:right">CPM</th><th style="text-align:right">Days Active</th><th style="text-align:right">Avg Daily Spend</th><th>Status</th></tr></thead><tbody>';
  Object.keys(vCamps).forEach(function(name) {
    var c = vCamps[name];
    var cpm = c.impressions > 0 ? (c.spend / c.impressions * 1000).toFixed(2) : '0.00';
    var dailyAvg = c.days > 0 ? c.spend / c.days : 0;
    var st = vibeStatus(name, c);
    campHtml += '<tr><td style="font-weight:600">' + name + '</td>';
    campHtml += '<td style="text-align:right">' + fmt(c.spend) + '</td>';
    campHtml += '<td style="text-align:right">' + fmtN(c.impressions) + '</td>';
    campHtml += '<td style="text-align:right">' + fmt(parseFloat(cpm)) + '</td>';
    campHtml += '<td style="text-align:right">' + c.days + '</td>';
    campHtml += '<td style="text-align:right">' + fmt(dailyAvg) + '</td>';
    campHtml += '<td><span class="tag tag-' + st + '">' + st.toUpperCase() + '</span></td></tr>';
  });
  campHtml += '</tbody></table>';
  document.getElementById('vibeCampaignTable').innerHTML = campHtml;

  var dates = [];
  var dateMap = {};
  vibe.forEach(function(r) {
    if (!dateMap[r.date]) { dateMap[r.date] = {spend:0,impressions:0}; dates.push(r.date); }
    dateMap[r.date].spend += r.spend;
    dateMap[r.date].impressions += r.impressions;
  });
  dates.sort();
  var dHtml = '<table><thead><tr><th>Date</th><th>Day</th><th style="text-align:right">Spend</th><th style="text-align:right">Impressions</th><th style="text-align:right">CPM</th></tr></thead><tbody>';
  dates.forEach(function(d) {
    var r = dateMap[d];
    var cpm = r.impressions > 0 ? (r.spend / r.impressions * 1000).toFixed(2) : '0.00';
    dHtml += '<tr><td style="font-weight:600">' + fmtDate(d) + '</td><td>' + getDayShort(d) + '</td>';
    dHtml += '<td style="text-align:right">' + fmt(r.spend) + '</td>';
    dHtml += '<td style="text-align:right">' + fmtN(r.impressions) + '</td>';
    dHtml += '<td style="text-align:right">' + fmt(parseFloat(cpm)) + '</td></tr>';
  });
  dHtml += '</tbody></table>';
  document.getElementById('vibeDailyTable').innerHTML = dHtml;

  // Vibe report content
  var rHtml = '';
  rHtml += '<div class="anomaly-box warning"><h4>\u26a0\ufe0f Apr 10 Underspend \u2014 $350 vs ~$279 Delivered</h4>';
  rHtml += '<p>Apr 10 showed a one-day delivery dip. Delivery recovered Apr 11+ and has been running stable at ~$350\u2013360/day. Check Vibe campaign pacing settings if this recurs. CPM remained stable, so this was a delivery volume issue, not pricing drift.</p></div>';
  rHtml += '<div class="anomaly-box success"><h4>TOF Campaign \u2014 Efficient Awareness at CPM ~$14</h4>';
  rHtml += '<p>TOF- HangSmart Traffic Campaign is delivering at CPM $13\u201318 \u2014 excellent for CTV awareness. Impression volume is 17,000\u201321,000/day. The lagged awareness effect (branded search lift + Amazon organic bump) typically manifests 3\u20137 days post-impression. Watch branded search volume and Amazon organic order velocity the week of Apr 15\u201321.</p></div>';
  rHtml += '<div class="anomaly-box info"><h4>Retargeting Campaign \u2014 CPM $21 Is Expected for Warm Audience</h4>';
  rHtml += '<p>Retargeting CPM is higher than TOF because the audience is smaller and more targeted. This is normal behavior. At $100/day spend driving ~4,800 impressions/day to your warmest audience, this is appropriately sized. Do not scale the retargeting campaign \u2014 scale TOF instead when ready.</p></div>';
  document.getElementById('vibeReportContent').innerHTML = rHtml;
}



